CREATE OR REPLACE FUNCTION fpb_get_bank_accno (as_memno char,as_bank_id char) RETURNS varchar AS $body$
DECLARE

  ls_bank_accno varchar(1000);
  li_count integer;

  cur_accno CURSOR FOR
  SELECT bank_acc_no
  from sc_mem_m_member_bank_accno
  where (membership_no = as_memno)
  and (bank_id = as_bank_id);
  type tabrowi_accno is table of cur_accno%rowtype index by integer;
  ltabrowi_accno tabrowi_accno;
BEGIN
  open cur_accno;
  fetch cur_accno bulk collect into ltabrowi_accno;
  close cur_accno;
  li_count := ltabrowi_accno.count;
  for i in 1..li_count loop
    ls_bank_accno := ls_bank_accno||','||trim(both ltabrowi_accno[i].bank_acc_no);
  end loop;
  if length(ls_bank_accno) > 0 then
    ls_bank_accno := substr(ls_bank_accno,2,length(ls_bank_accno));
  end if;

  return ls_bank_accno;
exception when others then CALL spa_dberror('fpb_get_bank_accno');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
